import { useState } from "react";

export default function Destinations({ openBooking }) {
  const [search, setSearch] = useState("");
  const [filter, setFilter] = useState("All");

  const destinations = [
    { name: "Paris, France", price: 1299, rating: 4.9, region: "Europe", tours: 8, tag: "Popular", image: "data:image/jpeg;base64," },
    { name: "Rome, Italy", price: 1199, rating: 4.8, region: "Europe", tours: 12, image: "https://images.unsplash.com/photo-1529260830199-42c24126f198" },
    { name: "Santorini, Greece", price: 1499, rating: 5, region: "Europe", tours: 6, tag: "Hot Deal", image: "data:image/jpeg;base64," },
    { name: "Dubai, UAE", price: 1699, rating: 4.7, region: "Middle East", tours: 8, image: "https://www.traveloffpath.com/wp-content/uploads/2022/11/Flying-To-Dubai-UAE-Finally-Lifts-All-Entry-Requirements-Returning-To-Normal-Travel-edited-scaled.jpg.webp" },
    { name: "Bali, Indonesia", price: 999, rating: 4.9, region: "Asia", tours: 15, tag: "Trending", image: "data:image/jpeg;base64," },
    { name: "Maldives", price: 2299, rating: 5, region: "Asia", tours: 7, image: "data:image/jpeg;base64," },

    { name: "London, UK", price: 1399, rating: 4.6, region: "Europe", tours: 10, image: "data:image/jpeg;base64," },
    { name: "New York, USA", price: 1599, rating: 4.8, region: "America", tours: 14, tag: "Popular", image: "https://monsieurmadameexplore.com/wp-content/uploads/2023/09/NYC-Top-of-The-Rock-1.jpg" },
    { name: "Tokyo, Japan", price: 1899, rating: 5, region: "Asia", tours: 12, tag: "Trending", image: "https://www.ytravelblog.com/wp-content/uploads/2022/09/Senso-Ji-Temple-tokyo.jpg" },
    { name: "Istanbul, Turkey", price: 1099, rating: 4.7, region: "Europe/Asia", tours: 9, image: "https://images.unsplash.com/photo-1524231757912-21f4fe3a7200" },
    { name: "Barcelona, Spain", price: 1299, rating: 4.8, region: "Europe", tours: 11, image: "https://barcelonesite.fr/images/que-faire-a-barcelone-ville.jpg" },
    { name: "Cairo, Egypt", price: 899, rating: 4.5, region: "Africa", tours: 7, image: "https://www.touristegypt.com/wp-content/uploads/2023/03/giza-pyramids-cairo-egypt-with-palm.jpg" },
    { name: "Marrakech, Morocco", price: 799, rating: 4.6, region: "Africa", tours: 6, tag: "Hot Deal", image: "https://images.unsplash.com/photo-1548013146-72479768bada" },
    { name: "Singapore", price: 1799, rating: 4.9, region: "Asia", tours: 10, image: "https://www.telegraph.co.uk/content/dam/travel/2025/11/05/TELEMMGLPICT000442637458_17623346578150_trans_NvBQzQNjv4BqqVzuuqpFlyLIwiB6NTmJwfSVWeZ_vEN7c6bHu2jJnT8.jpeg?imwidth=640" },
    { name: "Sydney, Australia", price: 2199, rating: 4.8, region: "Oceania", tours: 13, image: "https://content.r9cdn.net/rimg/dimg/12/98/b1e36771-city-2258-163f4d7f814.jpg?crop=true&width=1020&height=498" },
  ];

  const regions = ["All", "Europe", "Asia", "Africa", "America", "Middle East", "Oceania"];

  const filtered = destinations.filter((d) => {
    const matchSearch =
      d.name.toLowerCase().includes(search.toLowerCase());

    const matchFilter =
      filter === "All" || d.region.includes(filter);

    return matchSearch && matchFilter;
  });

  return (
    <div className="bg-[#0b1220] text-white px-6 py-20">

      {/* HEADER */}
      <h1 className="text-4xl text-center font-bold mb-3">
        🌍 Explore Destinations ✈️
      </h1>

      <p className="text-center text-gray-400 mb-10">
        {filtered.length} destinations found
      </p>

      {/* SEARCH + FILTER */}
      <div className="flex flex-col md:flex-row gap-4 justify-center mb-10">

        <input
          type="text"
          placeholder="Search destination..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className="px-4 py-2 rounded bg-black/40 border border-white/10 w-64"
        />

        <select
          value={filter}
          onChange={(e) => setFilter(e.target.value)}
          className="px-4 py-2 rounded bg-black/40 border border-white/10"
        >
          {regions.map((r, i) => (
            <option key={i}>{r}</option>
          ))}
        </select>

      </div>

      {/* GRID */}
      <div className="grid md:grid-cols-3 gap-6">

        {filtered.map((d, i) => (
          <div
            key={i}
            className="bg-black/40 rounded-2xl overflow-hidden transform hover:scale-105 transition duration-300 shadow-lg"
          >

            <img
              src={d.image}
              className="h-48 w-full object-cover"
            />

            <div className="p-4">

              {/* TAG */}
              {d.tag && (
                <span className="text-xs bg-cyan-500 px-2 py-1 rounded">
                  {d.tag}
                </span>
              )}

              <h2 className="text-xl font-bold mt-2">
                {d.name}
              </h2>

              <p className="text-gray-400 text-sm">
                {d.region}
              </p>

              <p className="mt-2">
                ⭐ {d.rating}
              </p>

              <p className="mt-2 text-cyan-400 font-bold">
                From {d.price}$
              </p>

              <p className="text-sm text-gray-300">
                {d.tours} Tours available
              </p>

              <button
                onClick={() => openBooking(d)}
                className="mt-4 w-full bg-cyan-500 py-2 rounded-xl hover:bg-cyan-600 transition"
              >
                View Tours
              </button>

            </div>
          </div>
        ))}

      </div>
    </div>
  );
}